const p = msg.payload;

if (!p || typeof p !== "object") {
    return null;
}

const messages = [];

function add(topic, payload, retain = false) {
    messages.push({
        topic,
        payload,
        qos: "0",
        retain: retain ? "true" : "false"
    });
}

if (p.type === "telemetry") {
    add("casa/ambiente/telemetria", JSON.stringify(p));
    if (p.temperature_c !== null && p.temperature_c !== undefined) {
        add("casa/ambiente/temperatura", String(p.temperature_c));
    }
    if (p.humidity_pct !== null && p.humidity_pct !== undefined) {
        add("casa/ambiente/umidade", String(p.humidity_pct));
    }
    add("casa/ambiente/luminosidade", String(p.light_raw));
    add("casa/estado/ventilador", p.fan_on ? "ON" : "OFF", true);
    add("casa/estado/luz", p.light_on ? "ON" : "OFF", true);
    add("casa/estado/movimento", p.motion ? "1" : "0");
    return [messages];
}

add("casa/sistema/eventos", JSON.stringify(p));
return [messages];

const topic = String(msg.topic || "");
let value = msg.payload;

if (Buffer.isBuffer(value)) {
    value = value.toString("utf8");
}

value = String(value).trim();

function boolTo01(v) {
    const s = String(v).trim().toLowerCase();

    if (["1", "true", "on", "ligar"].includes(s)) return "1";
    if (["0", "false", "off", "desligar"].includes(s)) return "0";

    return null;
}

const mapping = {
    "casa/config/temperatura_limite": "TEMP_LIMIT",
    "casa/config/histerese": "HYSTERESIS",
    "casa/config/luminosidade_limite": "LIGHT_THRESHOLD",
    "casa/config/auto_temperatura": "AUTO_TEMP",
    "casa/config/auto_iluminacao": "AUTO_LIGHT",
    "casa/config/exigir_movimento": "MOTION_REQUIRED",
    "casa/comando/ventilador": "FAN",
    "casa/comando/luz": "LIGHT"
};

if (topic === "casa/comando/status") {
    msg.payload = "STATUS\n";
    return msg;
}

const command = mapping[topic];

if (!command) {
    node.warn(`Topico sem mapeamento: ${topic}`);
    return null;
}

if (["AUTO_TEMP", "AUTO_LIGHT", "MOTION_REQUIRED", "FAN", "LIGHT"].includes(command)) {
    const normalized = boolTo01(value);

    if (normalized === null) {
        node.warn(`Payload booleano invalido em ${topic}: ${value}`);
        return null;
    }

    value = normalized;
}

msg.payload = `${command}=${value}\n`;
return msg;
